SELECT * FROM fund_quote 
WHERE fund_code = #{fundCode} 
AND quote_date = #{quoteDate}
ORDER BY quote_time_only DESC 
LIMIT 1

SELECT * FROM fund_quote


        AND fund_code LIKE CONCAT('%', #{fundCode}, '%')


        AND fund_name LIKE CONCAT('%', #{fundName}, '%')


        AND quote_date >= #{startDate}


        AND quote_date <= #{endDate}




        ORDER BY ${orderBy} ${orderDirection}


        ORDER BY fund_code ASC, quote_date DESC
